#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cuda_runtime.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

__global__ void initialize_data_kernel(float* f, int N_val) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N_val * N_val;

    if (idx < total) {
        int i = idx % N_val;
        int j = idx / N_val;

        if (i == 0 || i == N_val-1) {
            f[idx] = sinf(j * 2 * M_PI / (N_val - 1));
        }
        else if (j == 0 || j == N_val-1) {
            f[idx] = sinf(i * 2 * M_PI / (N_val - 1));
        }
        else {
            f[idx] = 0.0f;
        }
    }
}

__global__ void compute_iteration_kernel(float* f, float* f_old, float* error_ptr, int N_val) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_elems = (N_val - 2) * (N_val - 2);

    if (idx < total_elems) {
        int i = (idx % (N_val - 2)) + 1;
        int j = (idx / (N_val - 2)) + 1;

        float t = 0.25f * (f_old[IDX(i-1,j)] +
                           f_old[IDX(i+1,j)] +
                           f_old[IDX(i,j-1)] +
                           f_old[IDX(i,j+1)]);
        float df = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;

        atomicAdd(error_ptr, df * df);
    }
}

__global__ void copy_f_to_f_old_kernel(float* f, float* f_old, int N_val) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N_val * N_val;

    if (idx < total) {
        int i = idx % N_val;
        int j = idx / N_val;

        if (j >= 1 && j <= N_val-2 && i >= 1 && i <= N_val-2) {
            f_old[idx] = f[idx];
        }
    }
}

void initialize_data(float* f) {
    int total = N * N;
    int block_size = 256;
    int num_blocks = (total + block_size - 1) / block_size;

    initialize_data_kernel<<<num_blocks, block_size>>>(f, N);
    cudaDeviceSynchronize();
}

int main() {
    auto start_time = std::chrono::steady_clock::now();

    float* f;
    float* f_old;
    float* error_ptr;

    cudaMalloc(&f, N * N * sizeof(float));
    cudaMalloc(&f_old, N * N * sizeof(float));
    cudaMalloc(&error_ptr, sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f);
    initialize_data(f_old);

    const int max_iters = 10000;
    int num_iters = 0;

    auto start = std::chrono::steady_clock::now();

    while (error > tolerance && num_iters < max_iters) {
        error = 0.f;
        cudaMemcpy(error_ptr, &error, sizeof(float), cudaMemcpyHostToDevice);

        int total_elems = (N - 2) * (N - 2);
        int block_size = 256;
        int num_blocks = (total_elems + block_size - 1) / block_size;

        compute_iteration_kernel<<<num_blocks, block_size>>>(f, f_old, error_ptr, N);
        cudaDeviceSynchronize();

        cudaMemcpy(&error, error_ptr, sizeof(float), cudaMemcpyDeviceToHost);

        int total = N * N;
        num_blocks = (total + block_size - 1) / block_size;
        copy_f_to_f_old_kernel<<<num_blocks, block_size>>>(f, f_old, N);
        cudaDeviceSynchronize();

        error = sqrtf(error / (N * N));

        if (num_iters % 1000 == 0) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    if (error <= tolerance && num_iters < max_iters) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(f);
        cudaFree(f_old);
        cudaFree(error_ptr);
        return -1;
    }

    cudaFree(f);
    cudaFree(f_old);
    cudaFree(error_ptr);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
